#!/usr/bin/env bash
# topic-1.sh — 案例 决策助手 for 教育SaaS.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="教育SaaS"
TOPIC="案例"

usage() {
  cat <<EOF
topic-1.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 4 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-1.sh             # interactive
  ./topic-1.sh --dry-run   # walk through but no file
  ./topic-1.sh --json      # JSON to stdout
  ./topic-1.sh --explain   # show backing playbook rules + mental models
  ./topic-1.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 案例 主题下的 playbook 规则组合成交互树。

基于 4 条规则:
  • 如果 是进入北美高等教育市场 → 则 : 先做 LTI 1.3 认证 + SOC 2 Type II → 找 1-2 个种子学校做 pilot（学期制，至少跑
  • 如果 完课率低于预期 → 则 : 先做意图分层（casual learner / certificate seeker / degree pursue
  • 如果 面对开源 vs 商业选型争论 → 则 : 真实 TCO 计算必须包含运维人工成本 + 插件兼容性维护 + 升级 downtime。Moodle 总 TCO 在
  • 如果 是学术诚信检测 → 则 : AI 检测工具（Turnitin AI / GPTZero）误报率在 ESL 学生群体中显著高于平均（约 15-25

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "是进入北美高等教育市场"
  "完课率低于预期"
  "面对开源 vs 商业选型争论"
  "是学术诚信检测"
)
declare -a RULE_ACTIONS=(
  ": 先做 LTI 1.3 认证 + SOC 2 Type II → 找 1-2 个种子学校做 pilot（学期制，至少跑完一个完整学期）→ 拿到 case study 后攻 consortium/district deal。案例: Turnitin 先做单校 pilot → 扩展到 16,000+ 机构（约 20 年积累，T02-S005）"
  ": 先做意图分层（casual learner / certificate seeker / degree pursuer），对不同意图群体设不同基准。不要用统一完课率作 KPI。案例: Coursera 2014 年 Ho et al"
  ": 真实 TCO 计算必须包含运维人工成本 + 插件兼容性维护 + 升级 downtime。Moodle 总 TCO 在 3 年后可能超过 Canvas SaaS 如果没有专职维护团队。案例: UK Russell Group 大学从 Moodle 迁出趋势（约 2022-2025, T02-S003）"
  ": AI 检测工具（Turnitin AI / GPTZero）误报率在 ESL 学生群体中显著高于平均（约 15-25% false positive, 业内估）。必须保留教师人工判定为最终裁定，工具仅作辅助信号。案例: Turnitin 2024 增加\"AI writing indicator\"置信度分级而非二值判定（T03-S007）"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-1-decision"
fi
